  vars


    オプションの割り当て値。

  &reftitle.examples;

   SplFileObject::fscanf の例


<?php
$file = new SplFileObject("misc.txt");
while ($userinfo = $file->fscanf("%s %s %s")) {
   list ($name, $profession, $countrycode) = $userinfo;
   // $name $profession $countrycode で何かを行う
}
?>


   users.txt の内容


javier   argonaut    pe
hiroshi  sculptor    jp
robert   slacker     us
luigi    florist     it
